sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {

    if (isLoading)
        return;

    g_form.clearOptions('mode0');

    g_form.addOption(
        'mode0',
        '',
        '-- None --'
    );

    if (newValue == 'dell') {

        g_form.addOption(
            'mode0',
            'Latitude',
            'Latitude'
        );

        g_form.addOption(
            'mode0',
            'Inspiron',
            'Inspiron'
        );

        g_form.addOption(
            'mode0',
            'XPS',
            'XPS'
        );
    }

    else if (newValue == 'hp') {

        g_form.addOption(
            'mode0',
            'Pavilion',
            'Pavilion'
        );

        g_form.addOption(
            'mode0',
            'EliteBook',
            'EliteBook'
        );

        g_form.addOption(
            'mode0',
            'Victus',
            'Victus'
        );
    }

    else if (newValue == 'apple') {

        g_form.addOption(
            'mode0',
            'MacBook Air',
            'MacBook Air'
        );

        g_form.addOption(
            'mode0',
            'MacBook Pro',
            'MacBook Pro'
        );
    }
}
